/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Features:
 * - JSON payload formatting from NotificationPayload
 * - Configurable target URL
 * - Pluggable HTTP transport (default: in-memory capture for testing)
 *
 * Implements the NotificationAdapter interface. Must not throw from send().
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * Structure of the JSON payload sent to the webhook URL.
 */
export interface WebhookPayload {
  notificationId: string;
  type: string;
  recipient: string;
  subject: string;
  body: string;
  priority: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/**
 * Record of a webhook delivery attempt, for testing/inspection.
 */
export interface WebhookDelivery {
  url: string;
  payload: WebhookPayload;
  deliveredAt: Date;
}

/**
 * Transport function that handles the actual HTTP POST.
 * The default stores deliveries in-memory; inject a real transport for production.
 */
export type WebhookTransport = (url: string, payload: WebhookPayload) => Promise<void>;

export class WebhookNotificationAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];
  private url: string;
  private transport: WebhookTransport;

  constructor(options: {
    url: string;
    transport?: WebhookTransport;
  }) {
    this.url = options.url;
    this.transport = options.transport ?? ((url, payload) => {
      this.deliveries.push({ url, payload, deliveredAt: new Date() });
      return Promise.resolve();
    });
  }

  /**
   * Send a notification as a webhook POST.
   *
   * 1. Formats the notification payload as JSON
   * 2. POSTs it to the configured URL via the transport
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    try {
      const webhookPayload: WebhookPayload = {
        notificationId: payload.id,
        type: payload.type,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        priority: payload.priority,
        metadata: payload.metadata,
        timestamp: payload.createdAt.toISOString(),
      };

      await this.transport(this.url, webhookPayload);
      this.logger.info(`Webhook delivered to ${this.url}: ${payload.id}`);

      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to deliver webhook to ${this.url}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all webhook deliveries. Useful for testing.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Clear delivered webhooks. Useful for testing.
   */
  clearDeliveries(): void {
    this.deliveries = [];
  }
}

