function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channels: ['webhook'],
    priority: 'high',
    recipient: 'user-1',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date('2026-01-01'),
    ...overrides,
  };
}

describe('WebhookNotificationAdapter', () => {
  const webhookUrl = 'https://hooks.example.com/notifications';
  let adapter: WebhookNotificationAdapter;

  beforeEach(() => {
    adapter = new WebhookNotificationAdapter({ url: webhookUrl });
  });

  describe('channel property', () => {
    it('should be "webhook"', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('send()', () => {
    it('should deliver webhook for a valid payload', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.error).toBeUndefined();

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe(webhookUrl);
    });

    it('should format payload as WebhookPayload', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const delivery = adapter.getDeliveries()[0]!;
      expect(delivery.payload.notificationId).toBe('notif-0001');
      expect(delivery.payload.type).toBe('order-confirmation');
      expect(delivery.payload.recipient).toBe('user-1');
      expect(delivery.payload.subject).toBe('Order Confirmation: order-1');
      expect(delivery.payload.body).toContain('Widget x2');
      expect(delivery.payload.priority).toBe('high');
      expect(delivery.payload.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
      expect(delivery.payload.timestamp).toBe('2026-01-01T00:00:00.000Z');
    });

    it('should handle payload without metadata', async () => {
      const result = await adapter.send(makePayload({ metadata: undefined }));

      expect(result.success).toBe(true);
      const delivery = adapter.getDeliveries()[0]!;
      expect(delivery.payload.metadata).toBeUndefined();
    });

    it('should use custom transport when provided', async () => {
      const customTransport = vi.fn().mockResolvedValue(undefined);
      adapter = new WebhookNotificationAdapter({
        url: webhookUrl,
        transport: customTransport,
      });

      await adapter.send(makePayload());

      expect(customTransport).toHaveBeenCalledTimes(1);
      expect(customTransport).toHaveBeenCalledWith(webhookUrl, expect.objectContaining({
        notificationId: 'notif-0001',
        type: 'order-confirmation',
      }));
    });

    it('should catch transport errors and return failure', async () => {
      const failingTransport = vi.fn().mockRejectedValue(new Error('Connection refused'));
      adapter = new WebhookNotificationAdapter({
        url: webhookUrl,
        transport: failingTransport,
      });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });

    it('should handle non-Error exceptions', async () => {
      const failingTransport = vi.fn().mockRejectedValue('string error');
      adapter = new WebhookNotificationAdapter({
        url: webhookUrl,
        transport: failingTransport,
      });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown error');
    });

    it('should deliver multiple notifications independently', async () => {
      await adapter.send(makePayload({ id: 'notif-0001' }));
      await adapter.send(makePayload({ id: 'notif-0002', type: 'welcome' }));

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(2);
      expect(deliveries[0]?.payload.notificationId).toBe('notif-0001');
      expect(deliveries[1]?.payload.notificationId).toBe('notif-0002');
      expect(deliveries[1]?.payload.type).toBe('welcome');
    });

    it('should include all notification types in the payload', async () => {
      for (const type of ['order-confirmation', 'order-status-update', 'welcome', 'account-update'] as const) {
        adapter.clearDeliveries();
        await adapter.send(makePayload({ type }));
        expect(adapter.getDeliveries()[0]?.payload.type).toBe(type);
      }
    });

    it('should include all priority levels in the payload', async () => {
      for (const priority of ['low', 'normal', 'high'] as const) {
        adapter.clearDeliveries();
        await adapter.send(makePayload({ priority }));
        expect(adapter.getDeliveries()[0]?.payload.priority).toBe(priority);
      }
    });
  });

  describe('getDeliveries / clearDeliveries', () => {
    it('should return a copy of deliveries', async () => {
      await adapter.send(makePayload());

      const deliveries1 = adapter.getDeliveries();
      const deliveries2 = adapter.getDeliveries();
      expect(deliveries1).toEqual(deliveries2);
      expect(deliveries1).not.toBe(deliveries2);
    });

    it('should clear deliveries', async () => {
      await adapter.send(makePayload());
      expect(adapter.getDeliveries()).toHaveLength(1);

      adapter.clearDeliveries();
      expect(adapter.getDeliveries()).toHaveLength(0);
    });
  });
});
